const text = $json.message.text.trim();

// только время
const timeOnlyRegex = /^([0-1]?\d|2[0-3]):([0-5]\d)-([0-1]?\d|2[0-3]):([0-5]\d)$/;

// дата + время
const dateTimeRegex = /^(\d{1,2})\.(\d{1,2})\s+([0-1]?\d|2[0-3]):([0-5]\d)-([0-1]?\d|2[0-3]):([0-5]\d)$/;

let day;
let month;
let start;
let end;

// текущая дата по Киеву
const now = new Date();
const kyivParts = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Europe/Kyiv',
  day: 'numeric',
  month: 'numeric',
  year: 'numeric'
}).formatToParts(now);

const currentDay = Number(kyivParts.find(p => p.type === 'day').value);
const currentMonth = Number(kyivParts.find(p => p.type === 'month').value);
const currentYear = Number(kyivParts.find(p => p.type === 'year').value);

if (timeOnlyRegex.test(text)) {
  const [parsedStart, parsedEnd] = text.split('-');
  start = parsedStart;
  end = parsedEnd;
  day = currentDay;
  month = currentMonth;
} else {
  const match = text.match(dateTimeRegex);

  if (!match) {
    throw new Error(`INVALID_FORMAT|${$json.message.chat.id}`);
  }

  day = Number(match[1]);
  month = Number(match[2]);
  start = `${match[3]}:${match[4]}`;
  end = `${match[5]}:${match[6]}`;

  if (month !== currentMonth) {
    throw new Error(`INVALID_MONTH|${$json.message.chat.id}`);
  }

  const testDate = new Date(currentYear, month - 1, day);

  const isValidDate =
    testDate.getFullYear() === currentYear &&
    testDate.getMonth() === month - 1 &&
    testDate.getDate() === day;

  if (!isValidDate) {
    throw new Error(`INVALID_DATE|${$json.message.chat.id}`);
  }
}

function getWorkedTime(start, end) {
  const [sh, sm] = start.split(':').map(Number);
  const [eh, em] = end.split(':').map(Number);

  let startMin = sh * 60 + sm;
  let endMin = eh * 60 + em;

  if (endMin < startMin) {
    endMin += 24 * 60;
  }

  const diff = endMin - startMin;
  const hours = Math.floor(diff / 60);
  const minutes = diff % 60;

  return `${hours}:${String(minutes).padStart(2, '0')}`;
}

const workedTime = getWorkedTime(start, end);

return [{
  'User id': String($json.message.from.id),
  'Username': $input.first().json.message.from.first_name|| 'no_username',
  'day': String(day),
  'workedTime': workedTime,
  'chat_id': $json.message.chat.id
}];

const oldRow = $('Get row(s) in sheet').first().json;
const newData = $('Parse & Calc Hours1').first().json;

const targetDay = String(newData.day);

let updatedRow = {
  'User id': String(oldRow['User id']),
  'Username': oldRow['Username']
};

// аккуратно копируем только дни
for (let i = 1; i <= 31; i++) {
  updatedRow[String(i)] = oldRow[String(i)] || '';
}

// обновляем нужный день
updatedRow[targetDay] = newData.workedTime;

// если есть total hours — оставляем
if (oldRow['Total Hours']) {
  updatedRow['Total Hours'] = oldRow['Total Hours'];
}

return [{
  json: updatedRow
}];

const newData = $('Parse & Calc Hours1').first().json;

let row = {
  'User id': newData['User id'],
  'Username': newData['Username']
};

for (let i = 1; i <= 31; i++) {
  row[String(i)] = '';
}

row[String(newData.day)] = newData.workedTime;

return [row];

